export type DeferredPromise<T = void> = {
  promise: Promise<T>;
  resolve: (value: T) => void;
  reject: (reason: Error) => void;
};

export function createDeferredPromise<T = void>() {
  const deferred: DeferredPromise<T> = {} as DeferredPromise<T>;

  deferred.promise = new Promise((resolve, reject) => {
    deferred.resolve = resolve;
    deferred.reject = reject;
  });

  return deferred;
}

export async function getOptionalModule<T extends Promise<unknown>>(
  importPromise: T,
): Promise<Partial<Awaited<T>>> {
  try {
    return await importPromise;
  } catch {
    return {};
  }
}

export async function reloadPage() {
  if (!window.MobileWebKit?.navigation) {
    window.location.reload();

    return;
  }

  await window.MobileWebKit.navigation.reload();
}
